# MatrixGenerator.Tests.ps1
# Pester tests for the Environment Matrix Generator
# Following red/green TDD: each test is written before its implementation

BeforeAll {
    . "$PSScriptRoot/MatrixGenerator.ps1"
}

Describe 'New-BuildMatrix' {

    Context 'Basic cartesian product generation' {
        It 'generates all combinations of OS, language version, and feature flags' {
            $config = @{
                matrix = @{
                    os      = @('ubuntu-latest', 'windows-latest')
                    node    = @('18', '20')
                }
            }

            $result = New-BuildMatrix -Config $config
            # 2 OS x 2 node = 4 combinations
            $result.matrix.include | Should -HaveCount 4
        }

        It 'includes each dimension value in the output combinations' {
            $config = @{
                matrix = @{
                    os   = @('ubuntu-latest')
                    node = @('18', '20')
                }
            }

            $result = New-BuildMatrix -Config $config
            $result.matrix.include | Should -HaveCount 2
            $result.matrix.include[0].os | Should -Be 'ubuntu-latest'
            $result.matrix.include[0].node | Should -BeIn @('18', '20')
        }

        It 'handles a single dimension' {
            $config = @{
                matrix = @{
                    os = @('ubuntu-latest', 'macos-latest', 'windows-latest')
                }
            }

            $result = New-BuildMatrix -Config $config
            $result.matrix.include | Should -HaveCount 3
        }

        It 'handles three dimensions' {
            $config = @{
                matrix = @{
                    os      = @('ubuntu-latest', 'windows-latest')
                    node    = @('18', '20')
                    feature = @('enabled', 'disabled')
                }
            }

            $result = New-BuildMatrix -Config $config
            # 2 x 2 x 2 = 8
            $result.matrix.include | Should -HaveCount 8
        }
    }
}

