        $found | Should -Not -BeNullOrEmpty

        $found = $combos | Where-Object { $_.os -eq 'windows-latest' -and $_.node -eq '18' }
        $found | Should -Not -BeNullOrEmpty

        $found = $combos | Where-Object { $_.os -eq 'windows-latest' -and $_.node -eq '20' }
