    It 'returns true when all rule keys match' {
        $combo = @{ os = 'ubuntu'; node = '18' }
        $rule  = @{ os = 'ubuntu'; node = '18' }
        Test-CombinationMatchesRule -Combination $combo -Rule $rule | Should -BeTrue
