        $rule  = @{ os = 'ubuntu'; extra = 'yes' }
        Test-CombinationMatchesRule -Combination $combo -Rule $rule | Should -BeFalse
    }

    It 'returns true for an empty rule (matches everything)' {
        $combo = @{ os = 'ubuntu'; node = '18' }
