  1→# MatrixGenerator.ps1
  2→# Generates GitHub Actions strategy.matrix JSON from a configuration.
  3→#
  4→# Approach:
  5→#   1. Accept a config hashtable with matrix dimensions, include/exclude rules,
  6→#      max-parallel, fail-fast, and max-size settings.
  7→#   2. Compute the cartesian product of all matrix dimensions.
  8→#   3. Apply exclude rules to remove unwanted combinations.
  9→#   4. Merge in include rules (additional combinations).
 10→#   5. Validate the resulting matrix size against a configurable maximum (GitHub default: 256).
 11→#   6. Return a hashtable matching the GitHub Actions strategy schema.
 12→
 13→function Get-CartesianProduct {
 14→    <#
 15→    .SYNOPSIS
 16→        Computes the cartesian product of multiple arrays.
 17→    .DESCRIPTION
 18→        Given an ordered list of dimension names and a hashtable mapping each
 19→        name to an array of values, returns an array of hashtables representing
 20→        every combination.
 21→    #>
 22→    param(
 23→        [string[]]$DimensionNames,
 24→        [hashtable]$Dimensions
 25→    )
 26→
 27→    if ($DimensionNames.Count -eq 0) {
 28→        return @(@{})
 29→    }
 30→
 31→    # Start with a single empty combination
 32→    $combinations = @(@{})
 33→
 34→    foreach ($dimName in $DimensionNames) {
 35→        $values = $Dimensions[$dimName]
 36→        $newCombinations = @()
 37→
 38→        foreach ($combo in $combinations) {
 39→            foreach ($val in $values) {
 40→                # Clone the existing combination and add the new dimension
 41→                $newCombo = @{}
 42→                foreach ($key in $combo.Keys) {
 43→                    $newCombo[$key] = $combo[$key]
 44→                }
 45→                $newCombo[$dimName] = $val
 46→                $newCombinations += $newCombo
 47→            }
 48→        }
 49→        $combinations = $newCombinations
 50→    }
 51→
 52→    # Return the array — caller should wrap in @() to preserve array type
 53→    return $combinations
 54→}
 55→
 56→function Test-CombinationMatchesRule {
 57→    <#
 58→    .SYNOPSIS
 59→        Checks if a matrix combination matches an include/exclude rule.
 60→    .DESCRIPTION
 61→        A rule matches a combination if every key in the rule exists in the
 62→        combination with the same value.
 63→    #>
 64→    param(
 65→        [hashtable]$Combination,
 66→        [hashtable]$Rule
 67→    )
 68→
 69→    foreach ($key in $Rule.Keys) {
 70→        if (-not $Combination.ContainsKey($key)) { return $false }
 71→        if ($Combination[$key] -ne $Rule[$key]) { return $false }
 72→    }
 73→    return $true
 74→}
 75→
 76→function New-BuildMatrix {
 77→    <#
 78→    .SYNOPSIS
 79→        Generates a GitHub Actions strategy.matrix configuration.
 80→    .DESCRIPTION
 81→        Accepts a configuration hashtable and produces the complete matrix
 82→        JSON structure with all combinations, include/exclude rules applied,
 83→        and strategy settings (max-parallel, fail-fast).
 84→    .PARAMETER Config
 85→        A hashtable with the following optional keys:
 86→          - matrix: hashtable of dimension name -> array of values
 87→          - include: array of hashtables for additional combinations
 88→          - exclude: array of hashtables for combinations to remove
 89→          - max_parallel: integer limiting concurrent jobs
 90→          - fail_fast: boolean to stop all jobs on first failure
 91→          - max_size: integer maximum number of matrix combinations (default 256)
 92→    .OUTPUTS
 93→        A hashtable representing the full GitHub Actions strategy object.
 94→    #>
 95→    param(
 96→        [hashtable]$Config
 97→    )
 98→
 99→    # --- Validate input ---
100→    if (-not $Config) {
101→        throw "Config parameter is required."
102→    }
103→    if (-not $Config.ContainsKey('matrix') -or $null -eq $Config['matrix']) {
104→        throw "Config must contain a 'matrix' key with dimension definitions."
105→    }
106→
107→    $matrixDef = $Config['matrix']
108→    if ($matrixDef -isnot [hashtable]) {
109→        throw "The 'matrix' value must be a hashtable of dimension names to value arrays."
110→    }
111→
112→    # Validate each dimension has at least one value
113→    foreach ($key in $matrixDef.Keys) {
114→        $vals = $matrixDef[$key]
115→        if ($null -eq $vals -or ($vals -is [array] -and $vals.Count -eq 0)) {
116→            throw "Matrix dimension '$key' must have at least one value."
117→        }
118→    }
119→
120→    # --- Build the cartesian product ---
121→    # Sort dimension names for deterministic ordering
122→    $dimNames = @($matrixDef.Keys | Sort-Object)
123→    $combinations = @(Get-CartesianProduct -DimensionNames $dimNames -Dimensions $matrixDef)
124→
125→    # --- Apply exclude rules ---
126→    $excludeRules = @()
127→    if ($Config.ContainsKey('exclude') -and $null -ne $Config['exclude']) {
128→        $excludeRules = @($Config['exclude'])
129→        if ($excludeRules.Count -gt 0) {
130→            $filtered = @()
131→            foreach ($combo in $combinations) {
132→                $excluded = $false
133→                foreach ($rule in $excludeRules) {
134→                    if (Test-CombinationMatchesRule -Combination $combo -Rule $rule) {
135→                        $excluded = $true
136→                        break
137→                    }
138→                }
139→                if (-not $excluded) {
140→                    $filtered += $combo
141→                }
142→            }
143→            $combinations = @($filtered)
144→        }
145→    }
146→
147→    # --- Apply include rules ---
148→    # Include rules add extra combinations to the matrix.
149→    # If an include entry matches an existing combination on all its keys,
150→    # any additional keys in the include are merged into that combination.
151→    # If no existing combination matches, the include entry is added as a new row.
152→    if ($Config.ContainsKey('include') -and $null -ne $Config['include']) {
153→        $includeRules = @($Config['include'])
154→        foreach ($rule in $includeRules) {
155→            # Check if this include rule matches any existing combination
156→            # An include matches if all keys that overlap with dimension names have matching values
157→            $matched = $false
158→            $overlapKeys = @($rule.Keys | Where-Object { $dimNames -contains $_ })
159→
160→            if ($overlapKeys.Count -gt 0) {
161→                # Build a sub-rule with just the overlapping keys
162→                $overlapRule = @{}
163→                foreach ($k in $overlapKeys) {
164→                    $overlapRule[$k] = $rule[$k]
165→                }
166→
167→                for ($i = 0; $i -lt $combinations.Count; $i++) {
168→                    if (Test-CombinationMatchesRule -Combination $combinations[$i] -Rule $overlapRule) {
169→                        # Merge extra keys from the include rule into the existing combination
170→                        foreach ($k in $rule.Keys) {
171→                            $combinations[$i][$k] = $rule[$k]
172→                        }
173→                        $matched = $true
174→                    }
175→                }
176→            }
177→
178→            if (-not $matched) {
179→                # Add as a brand new combination
180→                $newCombo = @{}
181→                foreach ($k in $rule.Keys) {
182→                    $newCombo[$k] = $rule[$k]
183→                }
184→                $combinations += $newCombo
185→            }
186→        }
187→    }
188→
189→    # --- Validate matrix size ---
190→    $maxSize = 256  # GitHub Actions default limit
191→    if ($Config.ContainsKey('max_size') -and $null -ne $Config['max_size']) {
192→        $maxSize = [int]$Config['max_size']
193→        if ($maxSize -le 0) {
194→            throw "max_size must be a positive integer, got: $maxSize"
195→        }
196→    }
197→
198→    if ($combinations.Count -gt $maxSize) {
199→        throw "Matrix size ($($combinations.Count)) exceeds maximum allowed ($maxSize). Reduce dimensions or add exclude rules."
200→    }
201→
202→    # --- Build output structure ---
203→    # The output mirrors the GitHub Actions strategy schema:
204→    #   strategy:
205→    #     fail-fast: bool
206→    #     max-parallel: int
207→    #     matrix:
208→    #       include: [ {combination}, ... ]
209→    $strategy = @{
210→        matrix = @{
211→            include = @($combinations)
212→        }
213→    }
214→
215→    # Add fail-fast if specified
216→    if ($Config.ContainsKey('fail_fast')) {
217→        $strategy['fail-fast'] = [bool]$Config['fail_fast']
218→    }
219→
220→    # Add max-parallel if specified
221→    if ($Config.ContainsKey('max_parallel') -and $null -ne $Config['max_parallel']) {
222→        $maxParallel = [int]$Config['max_parallel']
223→        if ($maxParallel -le 0) {
224→            throw "max_parallel must be a positive integer, got: $maxParallel"
225→        }
226→        $strategy['max-parallel'] = $maxParallel
227→    }
228→
229→    return $strategy
230→}
231→
232→function ConvertTo-MatrixJson {
233→    <#
234→    .SYNOPSIS
235→        Convenience wrapper: accepts a config hashtable or JSON string and
236→        returns the matrix as a formatted JSON string.
237→    #>
238→    param(
239→        [Parameter(Mandatory)]
240→        $ConfigInput
241→    )
242→
243→    if ($ConfigInput -is [string]) {
244→        $Config = $ConfigInput | ConvertFrom-Json -AsHashtable
245→    } else {
246→        $Config = $ConfigInput
247→    }
248→
249→    $result = New-BuildMatrix -Config $Config
250→    return ($result | ConvertTo-Json -Depth 10)
251→}
